var subsequencesWithMiddleMode = function(nums) {
    const MOD = 1000000007;
    const n = nums.length;
    const comb2 = (x) => x >= 2 ? (x * (x - 1)) / 2 : 0;
    const freqL = new Map();
    const freqR = new Map();
    const get = (m, k) => m.has(k) ? m.get(k) : 0;
    for (const x of nums) freqR.set(x, get(freqR, x) + 1);
    let s2r = 0;
    for (const c of freqR.values()) s2r += c * c;
    let s2l = 0;
    let full1 = 0, full2 = 0, full3 = 0;
    let ans = 0;
    for (let m = 0; m < n; m++) {
        const v = nums[m];
        const r = get(freqR, v);
        const l = get(freqL, v);
        full1 -= l;
        full2 -= l * (2 * r - 1);
        full3 -= l * l;
        s2r -= (2 * r - 1);
        freqR.set(v, r - 1);
        const cr = r - 1;
        const cl = l;
        const otherL = m - cl;
        const otherR = (n - 1 - m) - cr;
        const os2l = s2l - cl * cl;
        const os2r = s2r - cr * cr;
        const c1 = full1 - cl * cr;
        const c2 = full2 - cl * cr * cr;
        const c3 = full3 - cl * cl * cr;

        let total = 0;
        if (cl >= 2 && cr >= 2) total += comb2(cl) * comb2(cr);
        if (cl >= 2) total += comb2(cl) * cr * otherR;
        if (cr >= 2) total += cl * otherL * comb2(cr);
        if (cl >= 2) total += comb2(cl) * comb2(otherR);
        if (cr >= 2) total += comb2(otherL) * comb2(cr);
        total += cl * otherL * cr * otherR;

        const pR2 = (otherR * otherR - os2r) / 2;
        const pL2 = (otherL * otherL - os2l) / 2;
        total += cl * (pR2 * otherL - otherR * c1 + c2);
        total += cr * (pL2 * otherR - otherL * c1 + c3);

        ans = (ans + total) % MOD;

        s2l += (2 * l + 1);
        full1 += cr;
        full2 += cr * cr;
        full3 += (2 * l + 1) * cr;
        freqL.set(v, l + 1);
    }
    return ans;
};
